def fusion(t1, t2):
    t = []
    while t1 and t2:
        if t1[0] &lt; t2[0]:
            t.append(t1.pop(0))
        else:
            t.append(t2.pop(0))
    if t1:
        t.extend(t1)
    else:
        t.extend(t2)
    return t


