Comptage des éléments d’un tableau

def comptage(tableau):
    d = {}
    for element in tableau:
        if element in d:
            d[element] += 1
        else:
            d[element] = 1
    return d


comptage(['Alice', 'Bob', 'Alice', 'Charles', 'Charles', 'Alice'])

{'Alice': 3, 'Bob': 1, 'Charles': 2}

